/**
 * Generate the project-root `./ui-forge.mjs` shim. SKILL_ROOT is resolved at
 * runtime so the file is portable across machines (safe to commit).
 */
import { join } from 'node:path';
import { atomicWrite } from '../fs-utils.js';
const TEMPLATE = `#!/usr/bin/env node
// ui-forge.mjs — local invocation shim
// Auto-generated by ui-forge@__VERSION__ — run \`ui-forge repair\` to regenerate.
// Resolves the skill root at runtime so this file is portable across machines.
import { spawnSync } from 'node:child_process';
import { existsSync } from 'node:fs';
import { homedir } from 'node:os';
import { join, resolve } from 'node:path';

const HELP = \`UI Forge — Local Invocation Shim

USAGE
  node ui-forge.mjs <command> [options] [args]

COMMANDS
  scan       Scan the project; write design/design-arch.json
  forge      Generate a component from refs
  verify     Run contract + standards validation on a file
  export     Export design bundle for Claude Design
  handoff    Fetch refs from a handoff URL
  mcp        Start the MCP server (long-running)

OPTIONS
  -h, --help     Show this help (or per-command help: <command> --help)
  -v, --version  Print version and skill location

EXAMPLES
  node ui-forge.mjs scan --quick
  node ui-forge.mjs forge --task "Hero section" --refs design/refs/hero.html
  node ui-forge.mjs verify app/components/Hero.tsx
\`;

function resolveSkillRoot() {
  if (process.env.UI_FORGE_SKILL_ROOT && existsSync(process.env.UI_FORGE_SKILL_ROOT)) {
    return process.env.UI_FORGE_SKILL_ROOT;
  }
  const localCandidates = [
    '.claude/skills/ui-forge',
    '.agents/skills/ui-forge',
    '.cursor/skills/ui-forge',
    '.codex/skills/ui-forge',
    '.copilot/skills/ui-forge',
    '.gemini/antigravity/skills/ui-forge',
  ];
  for (const rel of localCandidates) {
    const abs = resolve(process.cwd(), rel);
    if (existsSync(join(abs, 'scripts/invoke.js'))) return abs;
  }
  const globalCandidates = [
    join(homedir(), '.claude/skills/ui-forge'),
    join(homedir(), '.agents/skills/ui-forge'),
    join(homedir(), '.cursor/skills/ui-forge'),
  ];
  for (const abs of globalCandidates) {
    if (existsSync(join(abs, 'scripts/invoke.js'))) return abs;
  }
  console.error('ui-forge: skill not found. Run \`pnpm dlx ui-forge init\` or set UI_FORGE_SKILL_ROOT.');
  process.exit(1);
}

const SCRIPTS = {
  scan: 'scripts/scan.js',
  forge: 'scripts/invoke.js',
  verify: 'scripts/verify.js',
  export: 'scripts/export-design.js',
  handoff: 'scripts/fetch-handoff.js',
  mcp: 'scripts/mcp-server.js',
};

const [, , cmd, ...rest] = process.argv;

if (cmd === '--help' || cmd === '-h' || cmd === undefined) {
  console.log(HELP);
  process.exit(0);
}

if (cmd === '--version' || cmd === '-v') {
  // Version is stamped at install time; the installed skill dir no longer
  // ships skill.version (1.6.4). Re-run \`ui-forge repair\` after upgrading
  // the npm package to refresh this shim.
  const ver = '__VERSION__';
  console.log('ui-forge ' + ver);
  console.log('skill root: ' + resolveSkillRoot());
  process.exit(0);
}

if (!SCRIPTS[cmd]) {
  console.error('ui-forge: unknown command \\'' + cmd + '\\'');
  console.error("run 'node ui-forge.mjs --help' for usage");
  process.exit(2);
}

const r = spawnSync(process.execPath, [join(resolveSkillRoot(), SCRIPTS[cmd]), ...rest], { stdio: 'inherit' });
process.exit(r.status ?? 1);
`;
export function writeProjectCli(args) {
    const path = join(args.cwd, 'ui-forge.mjs');
    if (args.dryRun)
        return path;
    const body = TEMPLATE.replace(/__VERSION__/g, args.version);
    atomicWrite(path, body);
    return path;
}
export function projectCliPath(cwd) {
    return join(cwd, 'ui-forge.mjs');
}
